parameters.jsonBody:
={
  "contents": [{
    "parts": [{
      "text": "Classify this GitHub issue. Return ONLY valid JSON, no markdown.\n\nTitle: {{ $json.issue_title }}\n\nBody: {{ $json.issue_body }}\n\nReturn JSON with:\n- type: one of Bug, Feature Request, Documentation, Enhancement, Question\n- priority: one of Critical, High, Medium, Low\n- summary: one sentence analysis"
    }]
  }],
  "generationConfig": {
    "responseMimeType": "application/json",
    "responseSchema": {
      "type": "object",
      "properties": {
        "type": { "type": "string" },
        "priority": { "type": "string" },
        "summary": { "type": "string" }
      },
      "required": ["type", "priority", "summary"]
    }
  }
}
